INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5351545','Здрастуй, зимонько!','Музика: Анна Олєйнікова Слова: Лариса Ратич','uk','ukraine_1991',NULL,NULL,'http://minus.lviv.ua/minus/artist/%D0%9E%D0%BB%D1%94%D0%B9%D0%BD%D 1%96%D0%BA%D0%BE%D0%B2%D0%B0%20%20','Пісню виконує Софія Комарова.','Зимонька мережки замітала
І усіх нас радо привітала.
Хоч зима не хоче зігрівати -
Збереже тепло нам рідна хата.

Приспів:
Здрастуй, зимонько весела!
Хай міста сміються й села.
І засяють раз у раз
Іскри-вогники прикрас.
Хай радіють всі родини,
З ними ненька Україна
Багатіє в добрий час,
Гарні дні чекають нас!

Ой, які тепер чудові свята
Зимонька взялася дарувати.
Запалила вогник новорічний,
А іще - різдвяну зірку вічну!

Приспів. (2)','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5351545'), datetime('now')),datetime('now'));
