INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_535949','Встає хмара з-за Лиману','Музика: Кирило Стеценко Слова: Тарас Шевченко. Виконує: Бандурна Розмова','uk','ukr_ssr_1919_1991',NULL,'1963','1. Туристський пісенник "Де гори Карпати, де Писаний Камінь". - Літо, 1982. 2. Плавай, плавай, лебедонько. Народні пісні на слова Т. Шевченка. - К.: Музична Україна, 1989. С. 52. 3. Тарас Шевченко. Кобзар.','Акорди, подані в тексті відповідають мелодії із джерела 1 (музика Кирила Стеценка). Текст пісні є уривком з поезії "Тарасова ніч" Тараса Шевченка, яку можна прочитати тут: http://poetry.uazone.net/kobzar/tarasova_nich.html Залежно від обставин текст цієї патріотичної злободенної пісні формували із відповідних уривків поезії "Тарасова ніч". У джерелі 2 є посилання на першоджерело народного варіанту музики: Народна творчість та етнографія, 1963, кн. І.','Встає хмара з-за Лиману,
А другая з поля;
Зажурилась Україна -     |
Така її доля!            |(2)

Зажурилась, заплакала,
Як мала дитина.
Ніхто її не рятує...     |
Козачество гине.         |(2)

Гине слава, батьківщина;
Немає де дітись;
Виростають нехрещені     |
Козацькії діти.          |(2)

Кохаються не вінчані;
Без попа ховають;
Запродана жидам віра,    |
В церкву не пускають!    |(2)

Україно, Україно!
Серце моє, ненько!
Як згадаю твою долю,     |
Заплаче серденько!       |(2)
Акорди:
Встає хмара з-за Лиману,
А другая з поля;
Зажурилась Україна -     |(2)
Така її  до____ля!       |','[''pisni.org.ua'', ''cat:dumy'', ''cat:istorychni'', ''cat:nostalgia'', ''cat:suspilno-politychni'', ''Думи'', ''Історичні пісні'', ''Пісні з ностальгічними мотивами'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_535949'), datetime('now')),datetime('now'));
