INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5361106','Будь зі мною','Музика: Павло Ротар Слова: Павло Ротар. Виконує: Grohotsky','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Підбір акордів: Іван2001 Підбір акордів: Іван2001','Am
Я люблю холодні пори року,
C
Коли лежиш біля мене збоку
Em
Поряд із розплетеною косою,
G
На дворі холодно, а нас є двоє...
Я обожнюю темні ночі,
Коли в твоєму теплі сховатись хочу,
Де не видно наші болі...
Будеш іти! - Забери мене з собою!
Приспів:
Будь зі мною тихою струною!.. |
Розкажи як плавала одна       |
І у шторм, як не була собою   |
І про зраду розкажи,          |
Після терпкого вина...        | (2)
