INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_536242','Гуде вітер вельми в полі','Музика: Михайло Глінка Слова: Віктор Забіла. Виконує: Борис Гмиря, Анатолій Солов''яненко','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Гуде вітер вельми в полі,
Реве, ліс ламає.
Плаче козак молоденький,
Долю проклинає.
Гуде вітер вельми в полі,
Реве, ліс ламає.
Козак нудиться сердешний,
Що робить не знає.

Гуде вітер вельми в полі,
Реве, ліс ламає.
Козак стогне, бідолаха,
Сам собі гадає.
Ревеш,вітре, та не плачеш,
Бо тобі не тяжко,
Ти не знаєш в світі горя,
Та тобі й не важко.

Одірви ж од серця тугу,
Рознеси по полю,
Щоб не плакався я, бідний,
На нещасну долю!
А коли цього не зробиш,
Кинь мене у море -
Нехай зо мною потоне
Моє люте горе!','[''pisni.org.ua'', ''cat:nostalgia'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_536242'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_536242','Гуде вітер вельми в полі','Гуде вітер вельми в полі,
