INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5365949','Перший раз до школи','Музика: Анатолій Салогуб Слова: Анатолій Салогуб','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Перший раз у перший клас
Ми прийшли до школи!
Не забудемо цей день
Ми в житті ніколи!

Приспів:
Дзвінко, дзвоник,
Калатай, калатай!
Школа, нам скоріше
Двері відкривай!
Дзень, дзелень, дзелень!
Дзень, дзелень, дзелень!
Дзень, дзелень, дзелень!
Дзень, дзелень!

Перший дзвоник школярів
В класи закликає,
Перша вчителька наш клас
Радо зустрічає!

Приспів.','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5365949'), datetime('now')),datetime('now'));
