INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5371601','Люба дитинко','Слова: Зоряна Лісевич','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Люба дитинко, що тобі є?
Жаром палає личко твоє!
Мама подбає! Крихітко, знай,
Все буде добре! Спи, засинай!

Люба дитинко, горло пече,
Нежить замучив, з носа тече?
Мама подбає! Крихітко, знай,
Все буде добре! Спи, засинай!

Люба дитинко, чом ти не спиш?
Носик заклало, зимно, тремтиш?
Мама подбає! Крихітко, знай,
Все буде добре! Спи, засинай!

Люба дитинко, що тобі є?
Кашель заснути знов не дає?
Мама подбає! Крихітко, знай,
Все буде добре! Спи, засинай!','[''pisni.org.ua'', ''cat:pro-ditey'', ''Пісні про любов до дітей'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5371601'), datetime('now')),datetime('now'));
