INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5374343','Ніч покрила землю','(День Різдва!)','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Пісню виконує гурт Дитячі мрії.','Ніч покрила землю тихим
Покривалом теплих снів,
Знову місяць прокотився
Серед гір серед долин
І одна яскрава зірка
Засвітилась уночі -
На землі Господь з''явився
Став людиною як ми!

Приспів:
День Різдва! День Різдва!
Свого Сина Бог послав!
День Різдва! День Різдва
Мир і радість дарував!
Будем співами вітать,
Ісуса прославлять!
День Різдва! День Різдва!

Про народження Ісуса
Ангел Божий сповістив,
Хор небесний з похвалами
Ніс Христу славетний гімн,
Мудреці прийшли зі Сходу,
Щоб побачити Дитя
І вклонитись перед Богом,
Прославляючи Царя!

Приспів.

Нелегкі випробування
У Ісуса на шляху,
Шлях прославлений, величний
Випало пройти Йому
Та сім''я Його не знає,
Що готує доля їм
І Марія спочиває
З дорогим Дитям своїм...

Приспів.','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:shchedrivky'', ''cat:suchasni-pisni-rizdvo'', ''Колядки'', ''Щедрівки'', ''Сучасні пісні про Різдвяні свята'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5374343'), datetime('now')),datetime('now'));
