INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5373747','Чудова мить','Музика: MELOVIN Слова: MELOVIN, Luka Vovk. Виконує: MELOVIN','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Яка чудова мить,
Цця новорічна ніч -
Я так колись хотів її зустріти
Пліч-о-пліч з тобою,
Коли горять вогні навколо!
Ялинка, як ліхтар,
Злітається добро,
І кожна мить цієї ночі
З татовим вином,
Всі поруч: ти і я, і цілий світ!

Приспів:
Новий рік прийде
І сумніви зітре,
Любов нам принесе!
Ти знай, ми йдемо в новий рік,
Щоб бути щасливішими - я і ти!
Погане забувай,
І віри не втрачай в себе!
Ти віри не втрачай в себе!

Яка чудова мить,
Ця новорічна ніч -
Я так колись хотів її зустріти,
Де сімейне коло
І феєрверків цвіт навколо!
Згадаємо усе, що буде і було,
І стіл святковий ніби сяє
Маминим теплом,
Удома ти і я, і цілий світ!

Приспів.','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5373747'), datetime('now')),datetime('now'));
