INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5377900','Я прошу тебе, Ісусе',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Я прошу тебе, Ісусе,
Не лишай мене в біді,
Бо душа на волю рветься
У важкій тій самоті...
Серце крається на двоє,
Біль і страх в мені живе,
А Христос так промовляє:
Не журися, все мине!

Приспів:
Я візьму тебе на руки, |
Понесу туди, де Я -    |
І не буде вже розлуки, |
Бо дитина - ти - Моя!  | (2)

В мені сумніви бувають,
Недовіра ще живе,
Біль і смуток посилають -
І обличчя знов сумне...
Сльози котяться рікою
І в душі ще все пече,
А Христос так промовляє:
Не журися, все мине!

Приспів.','[''pisni.org.ua'', ''cat:christian'', ''cat:strasni'', ''Пісні на християнську тематику'', ''Страсні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5377900'), datetime('now')),datetime('now'));
