INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5375242','Сумно, сумно сонце сходить',NULL,'uk','ukr_ssr_1919_1991',NULL,NULL,'аудіозапис','Місце побутування: с. Вовче, Вовченська сільрада, Турківський район, Львівська область. Респондент: Музика Єва Василівна. Збирачі: Кльок Юлія, Винницька Ліля.','Сумно, сумно сонце сходить
В українському селі,
Покидають усі села -
Усі хлопці молоді.

Покинув я рідну хату,
Покинув я родину,
А сам пішов в темнім лісі
Пошукати хатину.

В тій хатині дуже сумно,
Бо без дверей, без вікна,
Вивезли в Сибір родину,
Сам остався сирота.

Ой, пішов я, шукаючи,
По тих дебрях лісових,
Сумна доля нас спіткала
Усіх хлопців молодих.','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5375242'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5375242','Сумно, сумно сонце сходить','Сумно, сумно сонце сходить
В українському селі,
Покидають усі села -
Усі хлопці молоді.

Покинув я рідну хату,
Покинув я родину,
А сам пішов в темнім лісі
Пошукати хатину.

В тій хатині дуже сумно,
Бо без дверей, без вікна,
Вивезли в Сибір родину,
Сам остався сирота.

Ой, пішов я, шукаючи,
По тих дебрях лісових,
Сумна доля нас спіткала
Усіх хлопців молодих.');
