INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5375545','Не стелися, кудрявчик','Українська народна пісня. Виконує: Етнографічний хор Гомін','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Не стелися, кудрявчик,
Не стелися,
Зелений кудрявчик,
Край мене.

Та край мого городця,
Та край мого,
Зелений кудрявчик,
Городця.

Проти мого віконця,
Проти мого,
Зелений кудрявчик,
Віконця.

Та не кажи мені вбиратись,
Та не кажи мені,
Зелений кудрявчик,
Вбиратись.

Йти в таночок гуляти,
Йти в таночок,
Зелений кудрявчик,
Гуляти.

Бо є в мене лихий муж,
Бо є в мене,
Зелений кудрявчик,
Лихий муж.

Буде мене картати,
Буде мене,
Зелений кудрявчик,
Картати.

Нагайкою краяти,
Нагайкою,
Зелений кудрявчик,
Краяти!','[''pisni.org.ua'', ''cat:podilski'', ''Пісні з Поділля'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5375545'), datetime('now')),datetime('now'));
