INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_538003','В Горах Грім гуде','Українська народна пісня. Виконує: Буття','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'1. У мандри. Збірник українських пісень для пластової молоді. - Мельбурн - Аделаїда, 1981','*У джерелі 1 відсутня остання в''язка пісні. Записана з пам''яті.','В Горах Грім гуде, хоч Зима паде,
Землю зорали гармати.
Гримить війна, дуднить Луна,       |
Дрижать зранені Карпати.           |(2)

Хто живий, вставай, боронити Край,
Вкритий вогнем і мерцями,
Не буде Тобі сумно в Боротьбі,     |
Між Січовими Стрільцями.           |(2)

Лютий кат прийшов проливати кров,
Взяти Народ Наш в неволю,
І море сліз у Край приніс,         |
Розбій і смерть, і недолю.         |(2)

Та вступився кат із Верхів Карпат,
Втік, наче вовк, манівцями,
Або тут і впав як у Бій попав      |
Із Січовими Стрільцями.            |(2)

Хто ж то там іде і Перед веде?
Диво! Це Наші Дівчата:
Личко як Мак, кругом Козак,        |
Душа Стрілецька Завзята.           |(2)

Не цілуйте Їх, на війні це гріх,
Краще вберіть Їх Вінками,
Слава цим Дочкам, Щирим Козачкам   |
Між Січовими Стрільцями!*          |(2)','[''pisni.org.ua'', ''cat:halycki'', ''cat:istorychni'', ''cat:strilecki'', ''cat:suspilno-politychni'', ''Пісні з Галичини'', ''Історичні пісні'', ''Стрілецькі пісні'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_538003'), datetime('now')),datetime('now'));
