INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_536508','До саду, дівчата, до саду','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1944','1. Українські народні пісні з Лемківщини. Зібрав О. Гижа. - К.: Музична Україна, 1972. С. 19. 2. Веснянки. Українські народні пісні. - К.: Музична Україна, 1988. С. 199.','Сіяти Павучки-павучки — Для кого і чому така подвійна настанова: сІяти Павучки! та — сіЯти, Павучки:-) Павучки сходять — як Зорі? Дівчата сіють/сіяють коли в якому Саду? Зорі теж було посіяно в Колядках:-) Згідно із джерелом 1 пісня записана у селі Висова повіту Горлиці 1944 року від Гатали Олени або Окарми Софії (нечітко зазначено). Діалектизми: зишла - зійшла; ищы - іще, ще; лучкы - луки, лучки; розишла (ся) - розійшла(ся); юж - вже. Гаїлки-Великдень: Українське свято Відродження Світа. Еротика, жарти, забави. сіяти павучкы --> Ой но на Морі Павутиноньки. Сіяти Павучки-павучки. До Саду Дівчата до Саду --> Ой білая паутина Там Біленьке Павутиння Ой Снодо Снодо Тонкая','До саду, дівчата, до саду,
Сіяти розсаду, розсаду!
Ищы наша розсада не зишла,      |
Юж ся наша любов розишла.       |(2)

Під грушку, дівчата, під грушку,
Сіяти петрушку, петрушку!
Ищы наша петрушка не зишла,     |
Юж ся наша любов розишла.       |(2)

На лучкы, дівчата, на лучкы,
Сіяти павучкы, павучкы!
Ищы наши павучкы не зишли,      |
Юж ся наши дівки розишли.       |(2)','[''pisni.org.ua'', ''cat:lemkivski'', ''cat:vesnyanky-hayivky'', ''Лемківські пісні'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_536508'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_536508','До саду, дівчата, до саду','До саду, дівчата, до саду,
