INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5380646','Гімн Кубані','Музика: Віктор Захарченко Слова: К. Образцов','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Ти, Кубань, Вітчизно рідная!
Віковий наш Богатир!
Хвилі волі, пісні долі
Ти несеш степами з гір.

Із країв південних, далеких
Із Туреччини, з війни
Щиро голови схиляємо
Твої, матінко, сини.

Ми про тебе пам''ятаючи,
Заспіваємо пісень
Про твої станиці вольнії,
Рідні хати, мирний день.

Ми про тебе пам''ятаючи,
Як про матінку свою,
З басурманом катом-варваром
Усі зійдемось в бою.

Ми про тебе пам''ятаючи,
Хіба не постоїмо?
За тебе і славу прадідів
Голови покладемо.

Ніби дань свою покірливо
Вид славетних прапорів
Кладемо Кубані рідній
До землі похил синів!','[''pisni.org.ua'', ''cat:himny-marshi'', ''Гимни та марші'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5380646'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5380646','Гімн Кубані','Ти, Кубань, Вітчизно рідная!
Віковий наш Богатир!
Хвилі волі, пісні долі
Ти несеш степами з гір.

Із країв південних, далеких
Із Туреччини, з війни
Щиро голови схиляємо
Твої, матінко, сини.

Ми про тебе пам''ятаючи,
Заспіваємо пісень
Про твої станиці вольнії,
Рідні хати, мирний день.

Ми про тебе пам''ятаючи,
Як про матінку свою,
З басурманом катом-варваром
Усі зійдемось в бою.

Ми про тебе пам''ятаючи,
