INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5379747','Що ж то іще буде','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Нам уроків задають
З кожним роком більше.
Перший клас, як інститут,
То ж міркуй скоріше.
Задають учителі
З іксами задачі,
Що старі професори,
Над завданням плачуть...

Приспів:
Що ж то іще буде?
Що ж то іще буде?
Що ж то іще буде?
Ой-ой-ой!

Вдома в нас переполох,
Твір писати знову.
Ні Шевченко, ні Франко
Не писав такого.
Я нікуди не ходжу,
Все пишу конспекти.
За комп''ютером сиджу,
Списую дискети.

Приспів.

Хочу я в кіно піти,
В лісі побувати.
Чудо - квіточку знайти,
Мрію загадати.
Опівночі спать іду,
Роздягтись несила.
Скоро, врешті, підросту,
Потім відпочину...

Приспів.

Не хвилюйтесь, все "окей!",
Труднощі здолаєм.
Ми у другий клас підем,
Швидко підростаєм.
Ми мости і кораблі
Станем будувати.
Ще й свій бізнес розпочнем,
Вийдем в депутати.

Приспів.

Дуже класно буде!
Дуже класно буде!
Дуже класно буде!
Посміхнись!','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5379747'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5379747','Що ж то іще буде','Нам уроків задають
З кожним роком більше.
Перший клас, як інститут,
То ж міркуй скоріше.
Задають учителі
З іксами задачі,
Що старі професори,
Над завданням плачуть...

Приспів:
Що ж то іще буде?
Що ж то іще буде?
Що ж то іще буде?
Ой-ой-ой!

Вдома в нас переполох,
Твір писати знову.
Ні Шевченко, ні Франко
Не писав такого.
Я нікуди не ходжу,
Все пишу конспекти.
За комп''ютером сиджу,
Списую дискети.

Приспів.

Хочу я в кіно піти,
В лісі побувати.
Чудо - квіточку знайти,
Мрію загадати.
Опівночі спать іду,
Роздягтись несила.
Скоро, врешті, підросту,
Потім відпочину...

Приспів.

Не хвилюйтесь, все "окей!",
Труднощі здолаєм.
Ми у другий клас підем,
Швидко підростаєм.
Ми мости і кораблі
Станем будувати.
Ще й свій бізнес розпочнем,
Вийдем в депутати.

Приспів.

Дуже класно буде!
Дуже класно буде!
Дуже класно буде!
Посміхнись!');
