INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5382106','Попід тоті сині гори','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Попід тоті сині гори
Крутії дороги,
Та не знаєш, моя мила,
Як то болять ноги.

Ой, гаю наш зелененький,
Гаю наш темненький,
Нема твого соловія,
Тому-с так сумненький.

На явора сонце гріє,
Явір зеленіє,
Пали мрачки понад млачки,
Рибка туманіє.

Ой, золоті підківочки,
Золоті, золоті,
Ліпше спати на камені,
Та як на болоті.','[''pisni.org.ua'', ''cat:kolomyyky'', ''Коломийки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5382106'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5382106','Попід тоті сині гори','Попід тоті сині гори
