INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5381545','У нас випускний','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Приспів:
У нас випускний, радіємо!
Хоч сумно нам та мріємо,
Що буде все в майбутньому!
Треба двері відкривати
У доросле та нове життя!
Плекаємо надію на те,
Що чекає у школі нас всіх
Учитель наш і країну поведемо
У щасливе та мирне буття!

Зустрілися давно,
Як в перший клас ішли,
Дитинство, юність у школі
Швидко так пройшли...
Все закінчилось:
І уроки, і дзвінки...
Спасибі, любі вчителі!.

Приспів.

І коли бувають сильнії вітри,
Не світить сонце, здавати треба ЗНО,
Та є надія: усім нам, друзі, пощастить!
Нам неодмінно пощастить!

Приспів.','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5381545'), datetime('now')),datetime('now'));
