INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5385444','Нічка новорічка','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Великим білокрилим птахом
Ялинка кутається в сніг,
А вечір, мов зайча-невдаха,
Стрибнув під неї і затих...
Ялинка віти опустила,
Щільніше голочки сплела,
Зручніше у заметі сіла
І колискову завела...

Приспів:
Від зірок по сніжку
Мерехтливе сяйво,
Місяць грає на ріжку -
Рік Новий стрічає!..
І роки Дід Мороз
Прокладає стежинку,
Щоби дітки змогли
Відшукати ялинку!

Дивився в ліс, як понад ставом
Плив місяць срібним ковзаном,
І кришталева тиша спала
У сон-дрімоти під крилом...
Пробігла стежкою лисичка,
Злякався вечір та й утік,
Настала нічка-новорічка,
Прийшов щасливий Новий Рік!

Приспів.','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5385444'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5385444','Нічка новорічка','Великим білокрилим птахом
Ялинка кутається в сніг,
А вечір, мов зайча-невдаха,
Стрибнув під неї і затих...
Ялинка віти опустила,
Щільніше голочки сплела,
Зручніше у заметі сіла
І колискову завела...

Приспів:
Від зірок по сніжку
Мерехтливе сяйво,
Місяць грає на ріжку -
Рік Новий стрічає!..
І роки Дід Мороз
Прокладає стежинку,
Щоби дітки змогли
Відшукати ялинку!

Дивився в ліс, як понад ставом
Плив місяць срібним ковзаном,
І кришталева тиша спала
У сон-дрімоти під крилом...
Пробігла стежкою лисичка,
