INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5391106','Вітрила','Виконує: Анастасія Нестеренко, MELOVIN','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Підбір акордів: bohdanko (pisni.org.ua)','Вступ: Am
Am
Коли від всіх тікаю,
Турботи забуваю,
Навколо очі самоти.
Am
Тобі я прошепочу,
Що знов відчути хочу,
Як разом із тобою ми.
Приспів:
Am
Ти - мої вітрила,
F
Музика моя.
Dm
Невагомі крила
E
Підіймають в небо.
Am
Дві частини серця,
F
Разом ти і я.
Dm
І мене не буде,
E
І нема без тебе.
Am
Не знаю, але вірю.
Душа плекає мрію,
Що шлях до тебе приведе.
Am
Земля летить все швидше,
За мить твоє обличчя
Мій погляд в натовпі знайде.
Приспів.
Програш: Am F Dm E x2
Модуляція: F#
Приспів:
Hm
Ти - мої вітрила,
G
Музика моя.
Em
Невагомі крила
F#
Підіймають в небо.
Hm
Дві частини серця,
G
Разом ти і я.
Em
І мене не буде,
F#
І нема без тебе.
Фінал: Hm G Em F# Hm','[''pisni.org.ua'', ''cat:lirychni'', ''Пісні про кохання, ліричні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5391106'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5391106','Вітрила','Вступ: Am
Am
Коли від всіх тікаю,
Турботи забуваю,
Навколо очі самоти.
Am
Тобі я прошепочу,
Що знов відчути хочу,
Як разом із тобою ми.
Приспів:
Am
Ти - мої вітрила,
F
Музика моя.
Dm
Невагомі крила
E
