INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5397747','Від ранкової зірки красніша','(О, Маріє, небесна Царице!)','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Від ранкової зірки красніша,
О, Маріє, небесна Царице,
Між зірок золотих найясніша,
Нема кращої в небі, як Ти!

Приспів:
Прекрасна Ти, як сонце,
Від місяця ясніша,
Між зорями у небі
Наймиліша, Маріє, Ти!

Мати Божа і Божого люду,
України квітучої Мати,
Поспіши наш народ рятувати,
Пригорни під свій ясний покров!

Приспів.

О, заступнице наша, Маріє,
Українського краю надіє,
Ми до Тебе всі молимось нині,
Дай нам віри й любові нам дай!

Приспів.

О, Пречистая Діво, Маріє,
Найдостойніша честі і слави,
Так вчини, щоби чистими стали
Наші помисли, вчинки, слова!

Приспів.

О, Маріє, очищення світу,
Нас прийми до своєї неволі,
Щоби через терпіння і болі
Двері неба відкрилися нам!

Приспів.','[''pisni.org.ua'', ''cat:do-bohorodyci'', ''Пісні до Богородиці'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5397747'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5397747','Від ранкової зірки красніша','Від ранкової зірки красніша,
