INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_538601','На Святого Яна Собітку палиме (2)','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Пара - любощі: Вогонь-Вода. Зілля-Коріння. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Розкладання Вогню. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. А де той Святий Ян що нам Три Огні клав. Три Гискри впало Три Морі стало. Були Світилки Яснії Зірки. Листки з приводу цієї Пісні: Українські релігійні роздуми про Бога. Щедрий Вечер, 13-14 січня. Маланки-Василь. Коза. Про Свято Івана Купала Стежки до листків про Українські традиції.','На Святого Яна Собітку палиме

Приспів:
Ей Яне-Яне Святий Яне

А де той Святий Ян що нам Три Огні клав
Освяти нам Зілля і вшитко Коріння','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_538601'), datetime('now')),datetime('now'));
