INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5388106','Гей у лузі червона калина похилилася','Українська народна пісня','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'аудіозапис','Записано у с.Ваньковичі (Бойківщина).','Гей у лузі червона калина похилилася,
Чого ж наша славна Україна зажурилася?
А ми тую червону калину підіймемо!         |
А ми нашу славну Україну, гей-гей,         |
Розвеселимо!                               | (2)

Не хилися, червона калино, все вгору рости!
Не журися, славна Україно, ми - твої сини!
Ми за тебе, червона калино, не забудем!    |
Ми для тебе, славна Україно, кращу долю    |
Здобудем!                                  | (2)

Не хилися, червона калино, маєш білий цвіт!
Не журися, славна Україно, маєш славний рід!
Білим цвітом, червона калино, заквітчайся! |
Славним родом, наша Україно, гей-гей,      |
Розвеселяйся!                              | (2)

Маширують стрільці січовії у кровавий тан,
Визволяти братів-українців з ворожих кайдан!
А ми наших братів-українців визволимо!     |
А ми нашу славну Україну, гей-гей,         |
Розвеселимо!                               | (2)

Там у полі ярої пшенички золотистий лан,
Розпочали стрільці січовії з ворогами тан!
А ми тую ярую пшеницю ізберемо!            |
А ми нашу славну Україну, гей-гей,         |
Розвеселимо!                               | (2)','[''pisni.org.ua'', ''cat:strilecki'', ''Стрілецькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5388106'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5388106','Гей у лузі червона калина похилилася','Гей у лузі червона калина похилилася,
Чого ж наша славна Україна зажурилася?
А ми тую червону калину підіймемо!         |
А ми нашу славну Україну, гей-гей,         |
Розвеселимо!                               | (2)

Не хилися, червона калино, все вгору рости!
Не журися, славна Україно, ми - твої сини!
Ми за тебе, червона калино, не забудем!    |
Ми для тебе, славна Україно, кращу долю    |
Здобудем!                                  | (2)

Не хилися, червона калино, маєш білий цвіт!
Не журися, славна Україно, маєш славний рід!
Білим цвітом, червона калино, заквітчайся! |
Славним родом, наша Україно, гей-гей,      |
Розвеселяйся!                              | (2)

Маширують стрільці січовії у кровавий тан,
Визволяти братів-українців з ворожих кайдан!
А ми наших братів-українців визволимо!     |
А ми нашу славну Україну, гей-гей,         |
Розвеселимо!                               | (2)

Там у полі ярої пшенички золотистий лан,
Розпочали стрільці січовії з ворогами тан!
А ми тую ярую пшеницю ізберемо!            |
А ми нашу славну Україну, гей-гей,         |
Розвеселимо!                               | (2)');
