INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_538646','На Івана на Купайла','Українська народна пісня. Виконує: Ніна Матвієнко','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Пісня-Гра. Пара - любощі: Мати. Дуб-Зілля. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. Робіть Дітки як я Мати. Листки з приводу цієї Пісні: Українські релігійні роздуми про Бога. Про Свято Івана Купала Стежки до листків про Українські традиції.','На Івана на Купайла
Ходила Відьма по Яйла
На Дуб лізла Кору гризла
З Дуба впала Зілля копала
З Дуба впала Зілля копала
Своїх Діток научала
Робіть Дітки як я Мати
Щоб уміли чарувати

Відміна:

На Івана,
На Івана на Купайлого
Бігла Відьма з под Майлого.

На Дуб,
На Дуб лізла, Кору гризла,
З Дуба впала, Зіллє рвала.

З Дуба впала,
З Дуба впала, Зіллє рвала,
Своїх Діток найучала.

Не йдіть, Дітки,
Не йдіть, Дітки, по чужий хліб,
Де йде, де йде чужий корінь.

А Дочка,
Єдна Дочка й не слухала,
За дойничку й потрухала.

За дойничку,
За дойничку потрухала,
Три дні дні не нюхала.

На четвертий,
На четвертий наїлася
Та й на печі розляглася.
Та й не встала','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_538646'), datetime('now')),datetime('now'));
