INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_538900','Чого Івасю змарнів-змарнів','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Пара - любощі: Воли. Шкода-Город. Серце-Личко. Івась-Маруся. Вибір Пари. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. На тім Листку написано Щедрий Вечір. Мов на Папері написаний. Івана Купала тай в Воду упала. Ой Твої Воли давно в Шкоді. Твої Коники в Шкоді. Хтось у Борі гукає Були Світилки Яснії Зірки. Ой Ти Іване Мій Паночку. Листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Українські релігійні роздуми про Бога. Про Свято Івана Купала Стежки до листків про Українські традиції.','Чого Івасю змарнів-змарнів
Чого шукаєш Волів-волів

Ой Твої Воли давно в Шкоді
Що й у Марусі на Вгороді

Ой там Маруся Воли гнала
Собі Івася сподобала

Ой Ти Івасю Серце моє
Сподобалося Личко Твоє

Ой не так личко як Ти Самий
Мов на Папері написаний

Ой на Папері-паперочку
На Тонкім Білім Серпаночку

На Тонкім Білім Серпаночку
Ой Ти Іване Мій Паночку','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_538900'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_538900','Чого Івасю змарнів-змарнів','Чого Івасю змарнів-змарнів
