INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5382704','Ой, задзвони, дзвонильнику','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, задзвони, дзвонильнику,
У голосні дзвінки,
Цілим дурнем можна звати,
Хто не має жінки.

Та задзвони, дзвонильнику,
У той дзвінок грімший,
А хто жінку собі бере,
Той дурень ще більший.

Ой, погану та не возьму,
Красної не буде,
Котрі були красні дівки —
Забрали їх люде.

Ой, коби я був судія,
Знав би я судити:
Всіх драбугів, волоцюгів
Дав би-м поженити,

Бо арешту, криміналу
За час мож ся збути,
А лукаву цокотуху
Не мож перебути.','[''pisni.org.ua'', ''cat:kolomyyky'', ''Коломийки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5382704'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5382704','Ой, задзвони, дзвонильнику','Ой, задзвони, дзвонильнику,
У голосні дзвінки,
Цілим дурнем можна звати,
Хто не має жінки.

