INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5400405','Христос воскрес!',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
Христос воскрес! Христос воскрес!
Христос воскрес! Алілуя!
Алілуя! Алілуя! Алілуя!
Христос воскрес!

О, смерте, відкликнись, о, смерте!
Де є моя смерть? Де ж її перемога?

Приспів.

О, браття, радіймо, всі браття!
Бо любимося взаємно тільки тому,
Що він воскрес!

Приспів.

Подяка Отцю хай буде,
Що веде нас у царство,
Де любов''ю живеться!

Приспів.

Якщо ми з Ним помираєм,
То й жити з Ним будем,
Співати з Ним будем: Алілуя!

Приспів.','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:voskresni'', ''Церковні пісні'', ''Воскресні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5400405'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5400405','Христос воскрес!','Приспів:
Христос воскрес! Христос воскрес!
Христос воскрес! Алілуя!
Алілуя! Алілуя! Алілуя!
Христос воскрес!

О, смерте, відкликнись, о, смерте!
Де є моя смерть? Де ж її перемога?

Приспів.

О, браття, радіймо, всі браття!
Бо любимося взаємно тільки тому,
Що він воскрес!

Приспів.

Подяка Отцю хай буде,
Що веде нас у царство,
Де любов''ю живеться!

Приспів.

Якщо ми з Ним помираєм,
То й жити з Ним будем,
Співати з Ним будем: Алілуя!

Приспів.');
