INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5405807','Тепер ми першокласники','Музика: Олександр Єрмолов Слова: Вадим Борисов','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Підросла дітвора, нам збиратись пора
В дім великий, що школою зветься.
У дитячім садку закінчилася гра,               |
Кожен з нас вже назад не вернеться...          | (2)

Приспів:
Тепер ми не малята, плаксиві дошкільнята,      |
А справжні першокласники, йдемо у перший клас! |
Садочок залишаємо, до школи поспішаємо,        |
Та завжди пам''ятатимем, рідненькі, ми про вас! | (2)

