INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5403141','Батька молитви','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Пісню виконують гурти "Вірність" і "Левит".','З ранніх років своїх у житті ще й до нині
В спекотні чи вночі бачу ти на колінах.
Тобі є що сказати до Бога в молитві,
Бо в тебе є сім''я, дорогі тобі діти.

Приспів:
Батька молитви так щирі і чисті
Йдуть у небо святе, у небесні обійстя.
Переповнені чаші йдуть до Божого трону
День і ніч за дітей, забуваючи втому.

Може ти не дасиш материнської ласки,
Може слово твоє не таке ніжне й часте,
Пригорнути мене забракує вже днини,
Бо така твоя батьківська доля в родині.

Приспів.

Що не скажеш в словах - теє виллєш в молитві,
Хоч не завжди до тебе уважні є діти,
Все одно ти нестимеш до Бога молитви,
Серце знає одне, це ж твої рідні діти!

Приспів.

Хай вирує життя тут бурхливе та грізне,
Є у мене в душі віра чиста і світла,
Що за мене завжди линуть в небо молитви,
А вони для мене, наче шолом у битві!

Приспів.

Скільки ще на землі нам призначено жити,
Хочу завжди я чуть щиру батька молитву.
Лиш одного прошу я, так щиро у Бога,
Хай не рветься твоя ще життєва дорога!

Приспів.','[''pisni.org.ua'', ''cat:pro-ditey'', ''Пісні про любов до дітей'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5403141'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5403141','Батька молитви','З ранніх років своїх у житті ще й до нині
