INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5398343','Матінко людства',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Матінко людства, Матінко Господня,
Ми, Твої діти, до Тебе приходим.
Нащадки Єви, молимо й благаєм:
Ти нас помилуй, Матінко благая!

Куди ж підемо у часи розпуки?
Мольби складемо в материнські руки,
Бо Божа Мати Серце добре має
І особливо бідним помагає.

Правда, ой, правда, все нам по заслугах,
Бо ми Христові недостойні слуги.
Та ти, Маріє, за дітей вступайся -
На нашу слабкість милосердно зглянься.

Серцю Марії небо гімн складає,
Матір Пречисту світ весь величає.
Серце Марії, будь для нас відкрите! -
З любов''ю просять Її вірні діти.','[''pisni.org.ua'', ''cat:do-bohorodyci'', ''Пісні до Богородиці'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5398343'), datetime('now')),datetime('now'));
