INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_54106','Гиля-гиля, сиві гуси','Українська народна пісня. Виконує: Оксана Білозір, Віктор Морозов, Гопак, Мен Саунд','uk','ukraine_before_1917',NULL,NULL,'Акорди: пісенник ОУМ "Спадщина"','* варіант: сірі гуси ** варіант: гиля, гиля до води *** варіант: на посаду, на посаді','Гиля-гиля, сиві гуси, *
Не колотіть води, **
Посватали дівчиноньку     |
D         G(Em)    | (2)
Плаче козак молодий.      |
