INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5404302','Різдвяна','Музика: Анничка Гнатишак Слова: Анничка Гнатишак','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Свічка різдвяна горить,
Пахне кутя і мед,
Вже благодатная мить настає.
Лине молитва увись,
Дзвонить малий колядник,
Хліб батько благословить,
Матінка стеле рушник.

Приспів:
Вже коляда дзвінкокрила
Щастя віщує народу,
Світові радість звістила
Зірка різдвяна зі Сходу!
Благословить добру долю
Людям Господня Дитина,
І до святкового столу
Сяде вкраїнська родина!

В кого ялинка сія,
В кого вусач-дідух,
В мирі співає сім''я коляду.
В кожну оселю прийдуть
З вісткою пастирі,
Тішаться щиро і ждуть
Першої в небі зорі!

Приспів.','[''pisni.org.ua'', ''cat:suchasni-pisni-rizdvo'', ''Сучасні пісні про Різдвяні свята'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5404302'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5404302','Різдвяна','Свічка різдвяна горить,
