INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5425949','Карпатський дощ','Музика: Ольга Монастирська Слова: Ольга Монастирська. Виконує: Ольга Монастирська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Накриває темний вечір
Ясну полонину,
Ми збираємо тим часом
Велику родину,
І, щоб ви не сумували,
То ми вам заграєм,
Щоб ся хмари розігнали,
Разом заспіваєм!

Приспів:
Дощ надворі іде,
Діаманти сипле з неба!
Знову трава росте зелена!
Ой, зелена!
У гаї солов''ї
Рапсодію співають,
І, напевно, кращої землі
Немає! Ой, немає!
Немає! Ой, немає!

Ой, збирайтеся довкола,
Ловіться за руки,
Щоб не було у родині
Довгої розлуки!
Як приємно, що сьогодні
Є вас так багато,
То ми можемо тим часом
Файно заспівати!

Приспів.','[''pisni.org.ua'', ''cat:druzhba'', ''Пісні про дружбу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5425949'), datetime('now')),datetime('now'));
