INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5424405','Вийди, вийди, Сонечко','Українська народна пісня. Виконує: NAVKA','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Вийди, вийди, Сонечко,
На дідове полечко,
На бабине зіллячко,
На наше подвір''ячко!

Вийди! Вийди!          |
