INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5429508','Жовте листячко летить','Музика: Наталія Май Слова: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Жовте листячко летить,
Танцює вальс, осінній вальс...
Знову дзвоник золотий
Нас кличе в клас,
Нас кличе в клас!..

Приспів:
Дні за днями дуже швидко пролетять
Та ніколи не повернуться назад...
Запам''ятай ці гарні дні          |
І вірних друзів всіх шкільних!.. | (2)

Жовте листя за вікном,
За літом йдуть осінні дні...
Промайнули, як кіно,
Шкільні роки, роки шкільні...

Приспів.

Дні за днями
Нначе в осінь листопад,
Вже ніколи не повернуться назад,
Та у душі ті гарні дні           |
І вірні друзі всі мої!..         | (2)','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5429508'), datetime('now')),datetime('now'));
