INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5429545','Ні для кого краще не буває','Музика: Василь Костючко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ні для кого краще не буває,
Хто по світу з друзями блукає!
Тим хто дружить, не страшні тривоги,
Нам любі для радості дороги!
Нам любі для радості дороги!

Ми своє завдання не забудем:
Сміх і радість ми приносим людям!
Замки нам і вежі небосходи
Не замінять у житті свободи!
Не замінять у житті свободи!

