INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5433141','Сніжинки-пушинки','Музика: Юрій Кудінов Слова: Олена Щепотьєва, Андрій Козій','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Новий рік, сніжинки в''ються,
Не впіймаєш, не даються,
І під покривалом сніжним
Казочки дрімають ніжно...
Все навкруг яксраво сяє,
Веселиться і співає!
Круг ялиночки зберемось,
Хоровод ми заведемо!

Приспів:
Сніжинки - пушинки
Танцюють, літають!
Сніжинки - пушинки
Зі святом вітають!
Сніжинки - пушинки
Тра-ля-ля-ля-ля!
Сніжинки - пушинки,
Радіє земля!

Вас вітаєм з Новим Роком!
Хай невпинним тихим кроком
Білий та пухнастий сніг
Щастя сипле на поріг!
Хай збуваються всі мрії,
Сподівання та надії!
Хай здоров''я не покине,
А добро у хату лине!

Приспів.','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5433141'), datetime('now')),datetime('now'));
