INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5438209','Last Christmas','Музика: George Michael Слова: George Michael','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Сніг навколо і веселий сміх
Нагадали нам, що прийшов Новий рік!
Щастя увірветься в наш дім,
В Новорічний вечір буде весело всім!
Радість всіх зігріє теплом,
І у кожній душі буде щастя й добро!
Свято! - Вже прийшов Новий рік,
Хай кохання завжди буде з вами навік!

Пісня об''єднає всіх нас
У цей радісний вечір, в Новорічний час!
Кульки і ялинка, і вогні,
Ми зібрались всі разом, ми співаєм пісні!
Друзі, подарунки для всіх,
І лунає в цей день всюди радісний сміх!
Щастя хай прилине до вас
В цю чарівну ніч, в Новорічний час!','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5438209'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5438209','Last Christmas','Сніг навколо і веселий сміх
Нагадали нам, що прийшов Новий рік!
Щастя увірветься в наш дім,
В Новорічний вечір буде весело всім!
Радість всіх зігріє теплом,
І у кожній душі буде щастя й добро!
Свято! - Вже прийшов Новий рік,
Хай кохання завжди буде з вами навік!

Пісня об''єднає всіх нас
У цей радісний вечір, в Новорічний час!
Кульки і ялинка, і вогні,
Ми зібрались всі разом, ми співаєм пісні!
Друзі, подарунки для всіх,
І лунає в цей день всюди радісний сміх!
Щастя хай прилине до вас
В цю чарівну ніч, в Новорічний час!');
