INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5439444','Мов поцілунок сонця','Музика: Богдан Весоловський Слова: Богдан Весоловський','uk','ukr_ssr_1919_1991',NULL,'1950','аудіозапис','Рідкісний запис Василя Тисяка на початку 1950-тих років, США.','Як я зустрів тебе одного дня,
Здавалось вже, що тільки ти одна
Без чар кохання
І щасливі дні зумієш дать мені!..

І хоч любив тебе я над усе
І вірив, що кохання не мине,
Та сил нема, щоб серцю приказать
Кого йому кохать!..

Мов поцілунок сонця,
Мов співи солов''я
Така палка й чарівна
Була любов твоя!..

Аж раз хтось ненадійно
Твоє серденько вкрав,
Із нашої любові лиш
Спомин нам остав...','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5439444'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5439444','Мов поцілунок сонця','Як я зустрів тебе одного дня,
