INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5424106','Пам''яті мало','Музика: Один в каное Слова: Один в каное. Виконує: Один в каное','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Всі мої стіни надумані,
Сірим пульсують артерії,
Люди бетонно задумані,
Люди не мають матерій...
Свої сувої нервів
Кутають в теплі халати,
В темні суворі меблі,
В світлі пусті палати...
Білим, усе білим
Світла додай, як слід,
Я маю на світло право,
Лишу на світлі слід!..

Приспів:
Пам''яті мало,           |
Шось тут було, я знала, |
Але забула...           | (2)

Я опускаюсь у товщу,
Я відчуваю тягу,
Я додаю тощо, а не розтягую...
Знаєш, я стукала-стукала,
Ти такий ватяний-ватяний,
Твої поламані ребра
Не розуміють натяку...
Мою останню віру
Топчуть стерильні бахіли,
Ти опускаєш руки -
Я піднімаю архіви...

Приспів.','[''pisni.org.ua'', ''cat:philosophic'', ''Філософські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5424106'), datetime('now')),datetime('now'));
