INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_544343','Тот Мій','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Лемківські співанки. Зібрав і упорядкував М. Соболевський. — К.: Музична Україна, 1967. — 320 с.','Пісня з добірки М.Соболевського: Лемківські співанки Діалектизми: доломан - верхній одяг, плащ; тот - той; червений - червоний; што - що.','Тот Мій Тот Мій
Што возит гній
Чорними Коровами     |
